import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void linearChain_srcToDst() {
        // 0-1-2-3-4, shortest from 0 to 4 is 4 edges
        int[][] edges = {{0,1},{1,2},{2,3},{3,4}};
        assertEquals(4, new Solution().shortestPath(5, edges, 0, 4));
    }

    @Test
    void srcEqualsDst_returnsZero() {
        int[][] edges = {{0,1},{1,2}};
        assertEquals(0, new Solution().shortestPath(3, edges, 1, 1));
    }

    @Test
    void unreachable_returnsMinusOne() {
        // Two disconnected components: {0,1} and {2,3}
        int[][] edges = {{0,1},{2,3}};
        assertEquals(-1, new Solution().shortestPath(4, edges, 0, 3));
    }

    @Test
    void shortcutEdge_picksShorterPath() {
        // Linear 0-1-2-3 plus shortcut 0-2; shortest 0→3 is 2 edges (0→2→3)
        int[][] edges = {{0,1},{1,2},{2,3},{0,2}};
        assertEquals(2, new Solution().shortestPath(4, edges, 0, 3));
    }

    @Test
    void singleNode_srcEqualsDst() {
        // n=1, no edges
        int[][] edges = {};
        assertEquals(0, new Solution().shortestPath(1, edges, 0, 0));
    }

    @Test
    void noEdges_differentNodes_unreachable() {
        int[][] edges = {};
        assertEquals(-1, new Solution().shortestPath(3, edges, 0, 2));
    }

    @Test
    void adjacentNodes_oneEdge() {
        int[][] edges = {{0,1},{1,2},{0,2}};
        assertEquals(1, new Solution().shortestPath(3, edges, 0, 1));
    }
}
